import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Eye, EyeOff, UserPlus, Zap } from 'lucide-react';
import AuthCard from '../components/AuthCard';

const RegisterPage = () => {
  const [formData, setFormData] = useState({ name: '', email: '', password: '', confirmPassword: '' });
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [focused, setFocused] = useState(null);

  const { register } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!formData.name || !formData.email || !formData.password || !formData.confirmPassword) {
      toast.error('Please fill in all fields');
      return;
    }

    if (formData.password !== formData.confirmPassword) {
      toast.error('Passwords do not match');
      return;
    }

    if (formData.password.length < 6) {
      toast.error('Password must be at least 6 characters');
      return;
    }

    setLoading(true);
    try {
      await register(formData);
      toast.success('Account created successfully!');
      navigate('/login');
    } catch (error) {
      toast.error(error.response?.data?.detail || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const labelStyle = (field) => ({
    display: 'block', 
    fontSize: '0.6rem', 
    fontWeight: 700,
    textTransform: 'uppercase', 
    letterSpacing: '0.18em',
    color: focused === field ? 'var(--accent-primary)' : 'var(--text-muted)',
    marginBottom: '0.4rem', 
    transition: 'color 0.2s ease',
  });

  const inputStyle = {
    width: '100%',
    boxSizing: 'border-box',
    WebkitBoxShadow: '0 0 0px 1000px var(--card-bg) inset',
    WebkitTextFillColor: 'var(--text-primary)',
    caretColor: 'var(--accent-primary)',
  };

  const inputProps = {
    className: 'cyber-input',
    required: true,
    style: inputStyle,
  };

  const PasswordField = ({ id, label, value, onChange, show, onToggle, autoComplete }) => (
    <div>
      <label htmlFor={id} style={labelStyle(id)}>
        {label}
      </label>
      <div style={{ position: 'relative' }}>
        <input
          id={id}
          type={show ? 'text' : 'password'}
          placeholder="••••••••"
          value={value}
          onChange={onChange}
          onFocus={() => setFocused(id)}
          onBlur={() => setFocused(null)}
          autoComplete={autoComplete}
          {...inputProps}
          style={{ ...inputProps, paddingRight: '3rem' }}
        />
        <button
          type="button"
          onClick={onToggle}
          aria-label={show ? 'Hide password' : 'Show password'}
          style={{
            position: 'absolute',
            right: '0.875rem',
            top: '50%',
            transform: 'translateY(-50%)',
            background: 'none',
            border: 'none',
            padding: 0,
            cursor: 'pointer',
            color: 'var(--text-muted)',
            display: 'flex',
            alignItems: 'center',
            transition: 'color 0.2s ease',
          }}
          onMouseEnter={e => e.currentTarget.style.color = 'var(--accent-primary)'}
          onMouseLeave={e => e.currentTarget.style.color = 'var(--text-muted)'}
        >
          {show ? <EyeOff size={15} /> : <Eye size={15} />}
        </button>
      </div>
    </div>
  );

  return (
    <AuthCard
      title="Create Account"
      subtitle="Initialize your node"
      icon={UserPlus}
      footerText={
        <>
          Already have an account?{' '}
          <Link
            to="/login"
            style={{ color: 'var(--accent-primary)', textDecoration: 'none', fontWeight: 700 }}
          >
            Sign in
          </Link>
        </>
      }
    >
      <form onSubmit={handleSubmit} noValidate style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
        <div>
          <label htmlFor="register-name" style={labelStyle('name')}>
            Full Name
          </label>
          <input
            id="register-name"
            type="text"
            placeholder="John Doe"
            value={formData.name}
            onChange={e => setFormData({...formData, name: e.target.value})}
            onFocus={() => setFocused('name')}
            onBlur={() => setFocused(null)}
            autoComplete="name"
            {...inputProps}
          />
        </div>

        <div>
          <label htmlFor="register-email" style={labelStyle('email')}>
            Email Address
          </label>
          <input
            id="register-email"
            type="email"
            placeholder="operator@finify.ai"
            value={formData.email}
            onChange={e => setFormData({...formData, email: e.target.value})}
            onFocus={() => setFocused('email')}
            onBlur={() => setFocused(null)}
            autoComplete="email"
            {...inputProps}
          />
        </div>

        <PasswordField
          id="register-password"
          label="Master Key"
          value={formData.password}
          onChange={e => setFormData({...formData, password: e.target.value})}
          show={showPassword}
          onToggle={() => setShowPassword(v => !v)}
          autoComplete="new-password"
        />

        <PasswordField
          id="register-confirm-password"
          label="Confirm Master Key"
          value={formData.confirmPassword}
          onChange={e => setFormData({...formData, confirmPassword: e.target.value})}
          show={showConfirmPassword}
          onToggle={() => setShowConfirmPassword(v => !v)}
          autoComplete="new-password"
        />

        <button
          type="submit"
          className="cyber-btn"
          disabled={loading}
          style={{ marginTop: '0.25rem' }}
        >
          {loading ? (
            <>
              <Zap size={13} style={{ animation: 'pulse 1s ease-in-out infinite' }} /> INITIALIZING...
            </>
          ) : (
            'Initialize Node'
          )}
        </button>
      </form>
    </AuthCard>
  );
};

export default RegisterPage;
